(1, 'Interview Invitation', 'Interview Invitation - {{position}}', 'Dear {{candidate_name}},\n\nThank you for your interest in the {{position}} position. We would like to invite you for an interview.\n\nDate: {{interview_date}}\nTime: {{interview_time}}\nLocation: {{location}}\n\nBest regards,\n{{company_name}}', 'Interview Invite', 1, 0, '2025-09-24 16:36:38', '2025-09-24 16:36:38'),
(2, 'Job Offer', 'Job Offer - {{position}}', 'Dear {{candidate_name}},\n\nCongratulations! We are pleased to offer you the position of {{position}}.\n\nPlease review the attached offer letter and let us know your decision.\n\nBest regards,\n{{company_name}}', 'Offer', 1, 0, '2025-09-24 16:36:38', '2025-09-24 16:36:38'),
(3, 'Rejection Notice', 'Application Update - {{position}}', 'Dear {{candidate_name}},\n\nThank you for your interest in the {{position}} position. After careful consideration, we have decided to move forward with other candidates.\n\nWe wish you the best in your job search.\n\nBest regards,\n{{company_name}}', 'Rejection', 1, 0, '2025-09-24 16:36:38', '2025-09-24 16:36:38');
